import java.time.*;
public class ImmutableDate {
    public static void main(String[] args) {
        LocalDate d = LocalDate.of(2024, 1, 1);
        d.plusDays(10);  // result discarded
        System.out.println(d);
        LocalDate d2 = d.plusDays(10);
        System.out.println(d2);
    }
}
